import{c as a,Q as i,j as l,m as e}from"./chunks/framework.5k1Nei9d.js";const u=JSON.parse('{"title":"iOS 越狱入门指南","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/ios-jailbreak.md","filePath":"tutorials/ios-jailbreak.md"}'),o={name:"tutorials/ios-jailbreak.md"};function r(d,t,n,s,h,c){return i(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="ios-越狱入门指南" tabindex="-1">iOS 越狱入门指南 <a class="header-anchor" href="#ios-越狱入门指南" aria-label="Permalink to &quot;iOS 越狱入门指南&quot;">​</a></h1><h2 id="什么是越狱" tabindex="-1">什么是越狱？ <a class="header-anchor" href="#什么是越狱" aria-label="Permalink to &quot;什么是越狱？&quot;">​</a></h2><p>越狱（Jailbreak）是获取 iOS 系统最高权限的过程。越狱后可以：</p><ul><li>安装第三方应用（非 App Store）</li><li>使用 Cydia / Sileo 安装插件</li><li>修改系统主题和界面</li><li>文件系统自由访问</li></ul><h2 id="越狱前必读" tabindex="-1">越狱前必读 <a class="header-anchor" href="#越狱前必读" aria-label="Permalink to &quot;越狱前必读&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">重要提醒</p><ul><li>越狱可能导致设备不稳定、耗电增加</li><li>部分应用（银行、游戏）会检测越狱并拒绝运行</li><li>越狱后官方保修可能失效</li><li><strong>建议使用备用机越狱</strong></li></ul></div><h2 id="当前可用越狱工具" tabindex="-1">当前可用越狱工具 <a class="header-anchor" href="#当前可用越狱工具" aria-label="Permalink to &quot;当前可用越狱工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>iOS 版本</th><th>类型</th></tr></thead><tbody><tr><td><strong>Dopamine</strong></td><td>iOS 15.0 - 15.4.1</td><td>半完美越狱</td></tr><tr><td><strong>palera1n</strong></td><td>iOS 15.0+ (A9-A11)</td><td>半完美越狱</td></tr><tr><td><strong>XinaA15</strong></td><td>iOS 15.0 - 15.4.1 (A12-A15)</td><td>半完美越狱</td></tr><tr><td><strong>unc0ver</strong></td><td>iOS 11.0 - 14.8</td><td>半完美越狱</td></tr><tr><td><strong>checkra1n</strong></td><td>iOS 12.0 - 14.8 (A7-A11)</td><td>checkm8 硬件漏洞</td></tr></tbody></table><h2 id="dopamine-越狱教程" tabindex="-1">Dopamine 越狱教程 <a class="header-anchor" href="#dopamine-越狱教程" aria-label="Permalink to &quot;Dopamine 越狱教程&quot;">​</a></h2><h3 id="步骤一-安装-dopamine" tabindex="-1">步骤一：安装 Dopamine <a class="header-anchor" href="#步骤一-安装-dopamine" aria-label="Permalink to &quot;步骤一：安装 Dopamine&quot;">​</a></h3><ol><li>使用 <a href="./ios-trollstore.html">TrollStore</a> 安装 Dopamine</li><li>或者使用 <a href="https://altstore.io/" target="_blank" rel="noreferrer">AltStore</a> / Sideloadly 自签安装</li></ol><h3 id="步骤二-执行越狱" tabindex="-1">步骤二：执行越狱 <a class="header-anchor" href="#步骤二-执行越狱" aria-label="Permalink to &quot;步骤二：执行越狱&quot;">​</a></h3><ol><li>打开 Dopamine 应用</li><li>点击「越狱」按钮</li><li>等待设备重启</li><li>桌面出现 <strong>Sileo</strong> 图标即越狱成功</li></ol><h3 id="步骤三-必装插件" tabindex="-1">步骤三：必装插件 <a class="header-anchor" href="#步骤三-必装插件" aria-label="Permalink to &quot;步骤三：必装插件&quot;">​</a></h3><ol><li><strong>ElleKit</strong> — 插件注入框架</li><li><strong>iCleaner Pro</strong> — 系统清理工具</li><li><strong>Filza</strong> — 文件管理器</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>越狱环境崩溃后需要重新越狱：重新打开 Dopamine → 点击越狱即可恢复插件。</p></div><h2 id="越狱后注意事项" tabindex="-1">越狱后注意事项 <a class="header-anchor" href="#越狱后注意事项" aria-label="Permalink to &quot;越狱后注意事项&quot;">​</a></h2><ul><li>不要随意卸载 Cydia / Sileo 自带的基础包</li><li>定期备份插件列表</li><li>谨慎添加来源不明的源</li></ul>',18)])])}const p=a(o,[["render",r]]);export{u as __pageData,p as default};
